// ═══ PROFİLLERİ UYGULA ═══
(function(){
  if(typeof PROF==="undefined")window.PROF={};
  if(typeof DISCOURSE==="undefined")window.DISCOURSE={};
  if(typeof B==="undefined")window.B={};
  if(typeof behReasons==="undefined")window.behReasons={};
  if(typeof profiles==="undefined")window.profiles={};

  Object.keys(PROFILES_WORLD).forEach(function(code){
    var p = PROFILES_WORLD[code];
    PROF[code] = p;

    // 1. Inject into profiles (UI overview panels)
    if(!profiles[code]) {
      profiles[code] = {
        leader: (p.discourse && p.discourse.leader) || "N/A",
        system: "N/A", 
        overview: p.overview || "",
        fpOrientation: p.foreignPolicy || "",
        issues: p.currentIssues || [],
        keyRelations: p.keyRelationships || "",
        econNote: p.economicProfile || ""
      };
    }

    // 2. Inject into B and behReasons (Behavioral game theory Engine)
    if(p.behavioral && !B[code]) {
      var beh = {};
      var brs = {};
      Object.keys(p.behavioral).forEach(function(k){
        beh[k] = p.behavioral[k].val;
        // Construct bilingual reasoned text
        brs[k] = { en: p.behavioral[k].reason, tr: p.behavioral[k].reason };
      });
      B[code] = beh;
      behReasons[code] = brs;
      if(typeof C!=="undefined" && C[code]) {
        C[code].beh = beh;
      }
    }

    // 3. Inject into DISCOURSE (NLP Engine)
    if(p.discourse && !DISCOURSE[code]) {
      var d = p.discourse;
      
      var st = (d.iranWarStance || "").toLowerCase();
      var finalSt = "neutral_concerned";
      if(st.indexOf("combat")>=0 || st.indexOf("war")>=0 || st.indexOf("belligerent")>=0) finalSt="active_participant";
      else if(st.indexOf("support")>=0 || st.indexOf("aligned")>=0) finalSt="cautious_support";
      else if(st.indexOf("neutral")>=0 || st.indexOf("not involved")>=0) finalSt="neutral_concerned";
      else if(st.indexOf("opponent")>=0 || st.indexOf("condemn")>=0) finalSt="condemned_all_violence";

      var br = (d.bricsMembership || "").toLowerCase();
      var finalBr = "non_member";
      if(br.indexOf("member")>=0 && br.indexOf("non")<0) finalBr="new_full_member";
      else if(br.indexOf("partner")>=0 || br.indexOf("interested")>=0 || br.indexOf("applied")>=0) finalBr="partner_not_full";
      else if(br.indexOf("opponent")>=0 || br.indexOf("adversarial")>=0) finalBr="opponent";

      DISCOURSE[code] = {
        leader: d.leader || "N/A",
        leaderSince: d.leaderSince || "N/A",
        dominantFrames: { 
          en: d.frames || [], 
          tr: d.frames || [] 
        },
        securitization: {
          level: d.securitization !== undefined ? d.securitization : 5,
          themes: { 
            en: d.securitizationThemes || [], 
            tr: d.securitizationThemes || [] 
          }
        },
        narrativeStyle: { 
          en: d.narrativeStyle || "", 
          tr: d.narrativeStyle || "" 
        },
        rhetoricalDevices: { 
          en: d.rhetoricalDevices || [], 
          tr: d.rhetoricalDevices || [] 
        },
        keyTerms: {},
        counterNarrativeTo: [],
        alignsWith: [],
        iranWarStance: finalSt,
        palestineRecognition: (typeof d.palestineRecognition==="string" && d.palestineRecognition.indexOf("Yes")>=0) || d.palestineRecognition===true,
        bricsMembership: finalBr
      };
    }
  });
  console.log("[PROFILES_WORLD] Injected data for " + Object.keys(PROFILES_WORLD).length + " countries into DISCOURSE, B, behReasons, and profiles engines.");
})();
